from beeai.events import MemoryEvent

def detect_memory_growth(events):
    memory_usage = []
    for event in events:
        if isinstance(event, MemoryEvent):
            memory_usage.append(event.context.memory_size)
            if len(memory_usage) > 10 and memory_usage[-1] > memory_usage[0] * 2:
                return {
                    'alert': 'UNBOUNDED_MEMORY_GROWTH',
                    'current_mb': memory_usage[-1] / (1024*1024),
                    'growth_factor': memory_usage[-1] / memory_usage[0]
                }
    return None

import re
from beeai.events import ToolCallEvent

def detect_tool_injection(event):
    if isinstance(event, ToolCallEvent):
        dangerous_patterns = [
            r'rm\s+-rf',
            r';\s*(cat|curl|wget)',
            r'\$\(.*?\)',
            r'`.*?`'
        ]
        input_str = str(event.input).lower()
        for pattern in dangerous_patterns:
            if re.search(pattern, input_str):
                return {
                    'alert': 'TOOL_INJECTION_DETECTED',
                    'tool': event.tool_name,
                    'suspicious_input': event.input,
                    'pattern_matched': pattern
                }
    return None

from beeai.llm import GraniteParser
from beeai.events import LLMResponseEvent

def detect_granite_parse_failures(events):
    failures = 0
    total_calls = 0
    for event in events:
        if isinstance(event, LLMResponseEvent) and event.model == 'granite':
            total_calls += 1
            try:
                GraniteParser.parse(event.raw_output)
            except Exception:
                failures += 1
    if total_calls > 5 and (failures / total_calls) > 0.3:
        return {
            'alert': 'GRANITE_PARSE_FAILURES',
            'failure_rate': f'{failures/total_calls:.1%}',
            'total_calls': total_calls
        }
    return None

