from beeai import AgentMiddleware
from beeai.context import AgentContext

class MemoryLimiterMiddleware(AgentMiddleware):
    def __init__(self, max_size_mb=50):
        self.max_size_mb = max_size_mb * 1024 * 1024

    def on_memory_update(self, context: AgentContext):
        if context.memory_size > self.max_size_mb:
            # Keep only last 100 messages
            messages = context.memory.messages[-100:]
            context.memory.clear()
            context.memory.add_messages(messages)
            print(f'Memory truncated to {len(messages)} messages')
        return context

from beeai.tools import AgentTool
import subprocess

class SecureTool(AgentTool):
    def __init__(self, base_tool):
        self.base_tool = base_tool

    def call(self, input_data):
        sanitized_input = self._sanitize_input(input_data)
        if not sanitized_input:
            raise ValueError('Input rejected: contains dangerous patterns')
        return self.base_tool.call(sanitized_input)

    def _sanitize_input(self, input_data):
        dangerous = ['rm -rf', ';', '`', '$(']
        input_str = str(input_data)
        return input_str if all(d not in input_str for d in dangerous) else None

from beeai.llm import GraniteParser
import json

class RobustGraniteParser:
    @staticmethod
    def parse(raw_output):
        try:
            return GraniteParser.parse(raw_output)
        except Exception as e:
            # Fallback: extract tool_calls from any JSON structure
            if 'tool_calls' in raw_output:
                return {'tool_calls': raw_output['tool_calls']}
            elif 'tools' in raw_output:
                return {'tool_calls': raw_output['tools']}
            # Default safe response
            return {'tool_calls': [], 'content': raw_output.get('content', 'Continue conversation')}
